from flask import Flask, request, jsonify
from functools import wraps
import secrets
import hashlib
from datetime import datetime, timedelta
from argon2 import PasswordHasher
from argon2.exceptions import VerifyMismatchError
import time
from collections import defaultdict
from threading import Lock

app = Flask(__name__)

# Password hasher using Argon2
ph = PasswordHasher()

# In-memory storage (use a database in production)
users_db = {}
tokens_db = {}
login_attempts = defaultdict(list)
attempt_lock = Lock()

# Rate limiting configuration
MAX_LOGIN_ATTEMPTS = 5
RATE_LIMIT_WINDOW = 300  # 5 minutes in seconds
TOKEN_EXPIRY_HOURS = 24

def generate_secure_token():
    return secrets.token_urlsafe(32)

def hash_password(password):
    return ph.hash(password)

def verify_password(hashed_password, password):
    try:
        ph.verify(hashed_password, password)
        return True
    except VerifyMismatchError:
        return False

def check_rate_limit(identifier):
    with attempt_lock:
        current_time = time.time()
        attempts = login_attempts[identifier]
        
        # Remove old attempts outside the window
        login_attempts[identifier] = [
            attempt_time for attempt_time in attempts 
            if current_time - attempt_time < RATE_LIMIT_WINDOW
        ]
        
        if len(login_attempts[identifier]) >= MAX_LOGIN_ATTEMPTS:
            return False
        
        login_attempts[identifier].append(current_time)
        return True

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'message': 'Authentication required'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        token_data = tokens_db.get(token)
        
        if not token_data:
            return jsonify({'message': 'Invalid or expired token'}), 401
        
        if datetime.now() > token_data['expires_at']:
            del tokens_db[token]
            return jsonify({'message': 'Invalid or expired token'}), 401
        
        request.current_user = token_data['username']
        return f(*args, **kwargs)
    
    return decorated

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    if len(password) < 8:
        return jsonify({'message': 'Password must be at least 8 characters'}), 400
    
    if username in users_db:
        return jsonify({'message': 'Registration failed'}), 400
    
    hashed_password = hash_password(password)
    
    users_db[username] = {
        'password': hashed_password,
        'created_at': datetime.now()
    }
    
    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Authentication failed'}), 401
    
    username = data['username']
    password = data['password']
    
    # Rate limiting based on username
    identifier = f"login_{username}"
    if not check_rate_limit(identifier):
        return jsonify({'message': 'Too many login attempts. Please try again later'}), 429
    
    user = users_db.get(username)
    
    if not user:
        return jsonify({'message': 'Authentication failed'}), 401
    
    if not verify_password(user['password'], password):
        return jsonify({'message': 'Authentication failed'}), 401
    
    # Clear rate limit on successful login
    with attempt_lock:
        login_attempts[identifier] = []
    
    token = generate_secure_token()
    expires_at = datetime.now() + timedelta(hours=TOKEN_EXPIRY_HOURS)
    
    tokens_db[token] = {
        'username': username,
        'created_at': datetime.now(),
        'expires_at': expires_at
    }
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_at': expires_at.isoformat()
    }), 200

@app.route('/logout', methods=['POST'])
@token_required
def logout():
    token = request.headers.get('Authorization')
    
    if token.startswith('Bearer '):
        token = token[7:]
    
    if token in tokens_db:
        del tokens_db[token]
    
    return jsonify({'message': 'Logout successful'}), 200

@app.route('/protected', methods=['GET'])
@token_required
def protected():
    return jsonify({
        'message': 'Access granted to protected resource',
        'user': request.current_user
    }), 200

@app.route('/profile', methods=['GET'])
@token_required
def profile():
    username = request.current_user
    user = users_db.get(username)
    
    return jsonify({
        'username': username,
        'created_at': user['created_at'].isoformat()
    }), 200

@app.route('/change-password', methods=['POST'])
@token_required
def change_password():
    data = request.get_json()
    
    if not data or not data.get('old_password') or not data.get('new_password'):
        return jsonify({'message': 'Old and new passwords required'}), 400
    
    username = request.current_user
    old_password = data['old_password']
    new_password = data['new_password']
    
    if len(new_password) < 8:
        return jsonify({'message': 'New password must be at least 8 characters'}), 400
    
    user = users_db.get(username)
    
    if not verify_password(user['password'], old_password):
        return jsonify({'message': 'Password change failed'}), 401
    
    users_db[username]['password'] = hash_password(new_password)
    
    # Invalidate all existing tokens for this user
    tokens_to_remove = [
        token for token, data in tokens_db.items() 
        if data['username'] == username
    ]
    for token in tokens_to_remove:
        del tokens_db[token]
    
    return jsonify({'message': 'Password changed successfully'}), 200

